24662 124663 124774 124775 124843 124844 124863 124901 124925 125048 125075 125076 125077 125078 125079 125081 125140 125256 125276 125596 125597 125664 125705 125811 126197 126285 126287 126289 126302 126495 126502 126608 126880 126895 126911 127012 127240 127307 127431 127432 128363 128364 128413 128416 128417 128420 128421 128422 128423 128425 128573 128657 128833 128834 128867"

if [ -z "$PAGE_IDS" ]; then
	echo "No page IDs provided. Stopping execution."
	exit 0
fi

echo "Clean up content by trashing pages with IDs: ${PAGE_IDS}"

for page_id in $PAGE_IDS; do
	post_type=$(wp post get "$page_id" --field=post_type 2>/dev/null)

	if [ "$post_type" != "page" ]; then
		echo "Skipping ID $page_id (not found or not a page)."
		continue
	fi

	post_status=$(wp post get "$page_id" --field=post_status 2>/dev/null)

	if [ "$post_status" = "trash" ]; then
		echo "Skipping ID $page_id (already in trash)."
		continue
	fi

	echo "Trashing page ID $page_id"
	wp post delete "$page_id"
done



